/* ── Portal Dropdown — renders to body to escape overflow clipping ── */
interface PortalDropdownProps {
  anchorRef: React.RefObject<HTMLElement>;
  open: boolean;
  onClose: () => void;
  children: React.ReactNode;
  minWidth?: number;
}

const PortalDropdown: React.FC<PortalDropdownProps> = ({
  anchorRef, open, onClose, children, minWidth = 180,
}) => {
  const [coords, setCoords] = useState({ top: 0, left: 0, width: 0 });

  // Recalculate position whenever it opens
  useEffect(() => {
    if (!open || !anchorRef.current) return;
    const rect = anchorRef.current.getBoundingClientRect();
    setCoords({
      top:   rect.bottom + 6,
      left:  rect.left,
      width: rect.width,
    });
  }, [open, anchorRef]);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (!anchorRef.current?.contains(e.target as Node)) onClose();
    };
    // slight delay so the button click that opens it doesn't immediately close it
    const id = setTimeout(() => document.addEventListener('mousedown', handler), 10);
    return () => {
      clearTimeout(id);
      document.removeEventListener('mousedown', handler);
    };
  }, [open, onClose, anchorRef]);

  if (!open) return null;

  const style: React.CSSProperties = {
    position: 'fixed',
    top:      coords.top,
    left:     coords.left,
    minWidth: Math.max(minWidth, coords.width),
    zIndex:   9999,
    background:    'var(--kb-surface)',
    border:        '1px solid var(--kb-border)',
    borderRadius:  'var(--r-lg)',
    boxShadow:     'var(--kb-shadow-lg)',
    overflow:      'hidden',
    animation:     'dropdownIn 0.15s cubic-bezier(0.34,1.4,0.64,1)',
  };

  return ReactDOM.createPortal(
    <div style={style}>{children}</div>,
    document.body,
  );
};

/* ── Main FilterBar ──────────────────────────────────── */
export const FilterBar: React.FC<FilterBarProps> = ({
  filter, members, onFilterChange, onClear,
}) => {
  const [openMenu, setOpenMenu] = useState<'assignee' | 'label' | 'due' | null>(null);

  const assigneeRef = useRef<HTMLButtonElement>(null);
  const labelRef    = useRef<HTMLButtonElement>(null);
  const dueRef      = useRef<HTMLButtonElement>(null);

  const toggle = (menu: 'assignee' | 'label' | 'due') => {
    setOpenMenu(prev => prev === menu ? null : menu);
  };

  const close = useCallback(() => setOpenMenu(null), []);

  const hasFilter = filter.assigneeId || filter.label || filter.dueDate;

  const activeAssigneeName = filter.assigneeId
    ? members.find(m => m.id === filter.assigneeId)?.name
    : null;
  const activeDueLabel = DUE_OPTIONS.find(d => d.value === filter.dueDate)?.label ?? null;

  return (
    <div className="kb-filter-bar">

      {/* Filter label */}
      <span className="kb-filter-bar__label">
        <IconFilter />
        Filter
      </span>
      <span className="kb-filter-bar__sep" />

      {/* ── Assignee chip ── */}
      <button
        ref={assigneeRef}
        className={`kb-filter-chip ${filter.assigneeId ? 'active' : ''}`}
        onClick={() => toggle('assignee')}
      >
        <IconUser />
        {activeAssigneeName ?? 'Assignee'}
        {!filter.assigneeId && <IconChevronDown />}
        {filter.assigneeId && (
          <span
            className="kb-filter-chip__clear"
            onClick={e => { e.stopPropagation(); onFilterChange({ assigneeId: null }); }}
          >
            <IconX />
          </span>
        )}
      </button>

      <PortalDropdown
        anchorRef={assigneeRef}
        open={openMenu === 'assignee'}
        onClose={close}
        minWidth={190}
      >
        <div className="kb-dropdown__header">Assignee</div>
        <button
          className={`kb-dropdown__item ${!filter.assigneeId ? 'kb-dropdown__item--checked' : ''}`}
          onClick={() => { onFilterChange({ assigneeId: null }); close(); }}
        >
          <span className="kb-dropdown__item-check">{!filter.assigneeId && <CheckIcon />}</span>
          All Members
        </button>
        {members.map(m => (
          <button
            key={m.id}
            className={`kb-dropdown__item ${filter.assigneeId === m.id ? 'kb-dropdown__item--checked' : ''}`}
            onClick={() => { onFilterChange({ assigneeId: m.id }); close(); }}
          >
            <span className="kb-dropdown__item-check">
              {filter.assigneeId === m.id && <CheckIcon />}
            </span>
            <div
              className="kb-avatar"
              style={{ background: m.color, width: 20, height: 20, fontSize: 9, flexShrink: 0, border: 'none', margin: 0 }}
            >
              {m.avatar}
            </div>
            {m.name}
          </button>
        ))}
      </PortalDropdown>

      {/* ── Label chip ── */}
      <button
        ref={labelRef}
        className={`kb-filter-chip ${filter.label ? 'active' : ''}`}
        onClick={() => toggle('label')}
      >
        <IconTag />
        {filter.label ?? 'Label'}
        {!filter.label && <IconChevronDown />}
        {filter.label && (
          <span
            className="kb-filter-chip__clear"
            onClick={e => { e.stopPropagation(); onFilterChange({ label: null }); }}
          >
            <IconX />
          </span>
        )}
      </button>

      <PortalDropdown
        anchorRef={labelRef}
        open={openMenu === 'label'}
        onClose={close}
        minWidth={170}
      >
        <div className="kb-dropdown__header">Label</div>
        <button
          className={`kb-dropdown__item ${!filter.label ? 'kb-dropdown__item--checked' : ''}`}
          onClick={() => { onFilterChange({ label: null }); close(); }}
        >
          <span className="kb-dropdown__item-check">{!filter.label && <CheckIcon />}</span>
          All Labels
        </button>
        {LABELS.map(l => (
          <button
            key={l}
            className={`kb-dropdown__item ${filter.label === l ? 'kb-dropdown__item--checked' : ''}`}
            onClick={() => { onFilterChange({ label: l }); close(); }}
          >
            <span className="kb-dropdown__item-check">{filter.label === l && <CheckIcon />}</span>
            <span className={`kb-label-dot kb-label-dot--${l}`} />
            {l}
          </button>
        ))}
      </PortalDropdown>

      {/* ── Due Date chip ── */}
      <button
        ref={dueRef}
        className={`kb-filter-chip ${filter.dueDate ? 'active' : ''}`}
        onClick={() => toggle('due')}
      >
        <IconCalendar />
        {activeDueLabel ?? 'Due Date'}
        {!filter.dueDate && <IconChevronDown />}
        {filter.dueDate && (
          <span
            className="kb-filter-chip__clear"
            onClick={e => { e.stopPropagation(); onFilterChange({ dueDate: null }); }}
          >
            <IconX />
          </span>
        )}
      </button>

      <PortalDropdown
        anchorRef={dueRef}
        open={openMenu === 'due'}
        onClose={close}
        minWidth={170}
      >
        <div className="kb-dropdown__header">Due Date</div>
        <button
          className={`kb-dropdown__item ${!filter.dueDate ? 'kb-dropdown__item--checked' : ''}`}
          onClick={() => { onFilterChange({ dueDate: null }); close(); }}
        >
          <span className="kb-dropdown__item-check">{!filter.dueDate && <CheckIcon />}</span>
          Any Date
        </button>
        {DUE_OPTIONS.map(d => (
          <button
            key={d.value}
            className={`kb-dropdown__item ${filter.dueDate === d.value ? 'kb-dropdown__item--checked' : ''}`}
            onClick={() => { onFilterChange({ dueDate: d.value as any }); close(); }}
          >
            <span className="kb-dropdown__item-check">
              {filter.dueDate === d.value && <CheckIcon />}
            </span>
            {d.label}
          </button>
        ))}
      </PortalDropdown>

      {/* ── Clear all ── */}
      {hasFilter && (
        <button className="kb-filter-chip active-clear" onClick={onClear}>
          <IconX />
          Clear Filters
        </button>
      )}
    </div>
  );
};
